SELECT AVG(area_sq_km) AS average_area_sq_km
FROM localities
WHERE status = 'Active' AND country = 'Australia' AND dc_id IS NOT NULL;

SELECT MAX(population) AS max_population
FROM localities
WHERE state = 'WA';

SELECT SUM(localities.population) AS total_population
FROM localities
WHERE localities.state = 'WA' AND localities.type = 'Delivery Area' AND localities.population > 3000;

SELECT COUNT(*)
FROM delivery_centres
WHERE state = 'WA';

SELECT AVG(population) AS average_population
  FROM localities
  WHERE status = 'Active';

SELECT locality_name
FROM localities
WHERE population = (SELECT MAX(population) FROM localities);

SELECT MIN(locality_id) 
FROM localities 
WHERE state = 'WA' AND dc_id = (SELECT dc_id FROM delivery_centres WHERE dc_name = 'PERTH DC');

SELECT u.email
FROM users u
WHERE u.role = 'end-user' AND u.user_name NOT IN (
    SELECT l.locality_name
    FROM localities l
);

SELECT l.locality_name
FROM localities l
WHERE l.dc_id = 1;
